import React, { useState } from "react";
import { Mic, Volume2 } from "lucide-react";
import { aiAPI } from "../../services/api";

export default function VoiceAdvisor() {
  const [listening, setListening] = useState(false);
  const [response, setResponse] = useState("");
  const [speaking, setSpeaking] = useState(false);

  const startListening = () => {
    // Check if browser supports speech recognition
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setResponse("Voice recognition is not supported in this browser.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = "en-US";

    recognition.onstart = () => {
      setListening(true);
      setResponse("Listening...");
    };

    recognition.onresult = async (event) => {
      const transcript = event.results[0][0].transcript;
      setListening(false);
      setResponse("Processing...");

      try {
        const res = await aiAPI.voiceAdvisor({ query: transcript });
        const reply = res.data.response || "No response received.";

        setResponse(reply);

        // 🔊 Speak response
        if ('speechSynthesis' in window) {
          window.speechSynthesis.cancel(); // clear previous
          const speech = new SpeechSynthesisUtterance(reply);
          speech.onstart = () => setSpeaking(true);
          speech.onend = () => setSpeaking(false);
          window.speechSynthesis.speak(speech);
        }
      } catch (err) {
        setResponse("Error communicating with AI Advisor.");
      }
    };

    recognition.onerror = () => {
      setListening(false);
      setResponse("Error occurred in recognition.");
    };

    recognition.start();
  };

  return (
    <div className="p-8 rounded-3xl bg-gradient-to-br from-white/5 to-white/[0.02] border border-white/10 backdrop-blur-xl shadow-2xl relative overflow-hidden mt-8 group transition-all duration-300 hover:border-white/20">
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-64 h-64 bg-indigo-500/10 rounded-full blur-[100px] -z-10 group-hover:bg-indigo-500/20 transition-all"></div>
      
      <div className="flex flex-col md:flex-row items-center justify-between gap-6 relative z-10">
        <div>
          <h2 className="text-xl font-bold mb-2 flex items-center gap-3">
            <div className="p-2 rounded-xl bg-indigo-500/20 text-indigo-400">
              <Mic size={20} />
            </div>
            Voice AI Coach
          </h2>
          <p className="text-white/60 text-sm max-w-md">Talk to your personal career advisor instead of typing. Ask out loud and get spoken advice tailored to you.</p>
        </div>

        <button
          onClick={startListening}
          disabled={listening || speaking}
          className={`shrink-0 px-6 py-3 rounded-2xl flex items-center gap-3 font-semibold transition-all duration-300 shadow-lg 
            ${listening 
              ? 'bg-red-500/20 border border-red-500/50 text-red-400 animate-pulse' 
              : speaking
              ? 'bg-green-500/20 border border-green-500/50 text-green-400'
              : 'bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 text-white hover:scale-105 hover:shadow-indigo-500/25 border border-white/10'}`}
        >
          {listening ? (
            <><div className="flex items-center gap-0.5"><div className="w-1 h-3 bg-red-400 rounded-full animate-bounce"></div><div className="w-1 h-4 bg-red-400 rounded-full animate-bounce delay-75"></div><div className="w-1 h-3 bg-red-400 rounded-full animate-bounce delay-150"></div></div> Listening...</>
          ) : speaking ? (
            <><Volume2 size={18} className="animate-pulse" /> Speaking...</>
          ) : (
            <><Mic size={18} /> Tap to Speak</>
          )}
        </button>
      </div>

      {(response && response !== "Listening..." && response !== "Processing...") && (
        <div className="mt-6 p-4 rounded-xl bg-white/5 border border-white/10 text-white/80 text-sm italic leading-relaxed backdrop-blur-md flex items-start gap-4">
          <Volume2 size={16} className="text-indigo-400 mt-1 shrink-0" />
          <p>"{response}"</p>
        </div>
      )}
    </div>
  );
}
